    &lt;inertial&gt;
        &lt;mass value="${m}" /&gt;
        &lt;origin xyz="${o_xyz}" rpy="${o_rpy}" /&gt;

        &lt;!-- Matriz Inercial de volumen para un Cilindro Sólido --&gt;
